"use client";

import { ExternalLink, Loader2, Mail } from "lucide-react";
import type React from "react";
import { useEffect, useState } from "react";
import { Button } from "@/components/ui/button";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
} from "@/components/ui/dialog";
import { Textarea } from "@/components/ui/textarea";
import { submitFeedback } from "@/server/actions/feedback-actions";

interface FeedbackDialogProps {
  trigger?: React.ReactNode;
  className?: string;
}

export const FeedbackDialog = ({ trigger, className }: FeedbackDialogProps) => {
  const [loading, setLoading] = useState(false);
  const [success, setSuccess] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [feedback, setFeedback] = useState("");
  const [open, setOpen] = useState(false);
  const [showEmailFallback, setShowEmailFallback] = useState(false);
  const [mailtoLink, setMailtoLink] = useState<string | null>(null);

  // Reset form when dialog closes
  useEffect(() => {
    if (!open) {
      // Small delay to allow animation to complete
      const timeout = setTimeout(() => {
        setFeedback("");
        setError(null);
        setSuccess(false);
        setShowEmailFallback(false);
      }, 300);
      return () => clearTimeout(timeout);
    }
  }, [open]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!feedback.trim()) return;

    setLoading(true);
    setSuccess(false);
    setError(null);
    setShowEmailFallback(false);

    try {
      const result = await submitFeedback({
        content: feedback.trim(),
        source: "dialog",
      });

      if (result.success) {
        if (result.requiresEmailFallback) {
          setShowEmailFallback(true);
          if (result.mailtoLink) setMailtoLink(result.mailtoLink);
        } else {
          setSuccess(true);
          // Close dialog after success
          const timeout = setTimeout(() => {
            setOpen(false);
          }, 1500);
          return () => clearTimeout(timeout);
        }
      } else {
        setError(result.error ?? "Failed to send feedback. Please try again.");
      }
    } catch (error) {
      setError("Failed to send feedback. Please try again.");
      console.error("Feedback submission error:", error);
    } finally {
      setLoading(false);
    }
  };

  const handleEmailFallback = () => {
    if (mailtoLink) window.open(mailtoLink, "_blank");
    setSuccess(true);
    // Close dialog after opening email
    const timeout = setTimeout(() => {
      setOpen(false);
    }, 1500);
    return () => clearTimeout(timeout);
  };

  return (
    <Dialog open={open} onOpenChange={setOpen}>
      <DialogTrigger className="w-full" asChild>
        <div className="w-full">
          {trigger ?? (
            <Button variant="ghost" className={`w-full ${className}`}>
              Feedback
            </Button>
          )}
        </div>
      </DialogTrigger>
      <DialogContent className="sm:max-w-md">
        <form onSubmit={handleSubmit}>
          <DialogHeader>
            <DialogTitle>Send Feedback</DialogTitle>
            <DialogDescription>
              Help us improve by sharing your thoughts, suggestions, or reporting issues.
            </DialogDescription>
          </DialogHeader>
          <div className="mt-4 space-y-4">
            <Textarea
              value={feedback}
              onChange={(e) => setFeedback(e.target.value)}
              placeholder="Your feedback..."
              className="min-h-[100px]"
              disabled={loading}
            />
            {error && <p className="text-sm text-red-500">{error}</p>}
            {success && <p className="text-sm text-green-500">Thank you for your feedback! 🚀</p>}
            {showEmailFallback && (
              <div className="p-4 bg-blue-50 dark:bg-blue-950/20 border border-blue-200 dark:border-blue-800 rounded-lg">
                <div className="flex items-start gap-3">
                  <Mail className="h-5 w-5 text-blue-600 dark:text-blue-400 mt-0.5" />
                  <div className="space-y-2">
                    <p className="text-sm text-blue-800 dark:text-blue-200">
                      Email service not configured. Click below to open your email client:
                    </p>
                    <Button
                      type="button"
                      size="sm"
                      onClick={handleEmailFallback}
                      className="bg-blue-600 hover:bg-blue-700 text-white"
                    >
                      <ExternalLink className="mr-2 h-4 w-4" />
                      Open Email Client
                    </Button>
                  </div>
                </div>
              </div>
            )}
          </div>
          <DialogFooter className="mt-4">
            <Button
              type="button"
              variant="outline"
              onClick={() => setOpen(false)}
              disabled={loading}
            >
              Cancel
            </Button>
            {!showEmailFallback && (
              <Button type="submit" disabled={loading || !feedback.trim()}>
                {loading ? (
                  <>
                    <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                    Sending...
                  </>
                ) : success ? (
                  "Sent!"
                ) : (
                  "Send Feedback"
                )}
              </Button>
            )}
          </DialogFooter>
        </form>
      </DialogContent>
    </Dialog>
  );
};

"use client";

import { ExternalLink, Mail } from "lucide-react";
import { useState } from "react";
import { Button } from "@/components/ui/button";
import {
  PopoverCloseButton,
  PopoverContent,
  PopoverFooter,
  PopoverForm,
  PopoverHeader,
  PopoverRoot,
  PopoverSubmitButton,
  PopoverTextarea,
  PopoverTrigger,
} from "@/components/ui/cults/animated-popover";
import { submitFeedback } from "@/server/actions/feedback-actions";

export const FeedbackPopover = () => {
  const [loading, setLoading] = useState(false);
  const [success, setSuccess] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [showEmailFallback, setShowEmailFallback] = useState(false);
  const [feedbackContent, setFeedbackContent] = useState("");
  const [mailtoLink, setMailtoLink] = useState<string | null>(null);

  const handleSubmit = async (content: string) => {
    setLoading(true);
    setSuccess(false);
    setError(null);
    setShowEmailFallback(false);
    setFeedbackContent(content);

    try {
      const result = await submitFeedback({
        content,
        source: "popover",
      });

      if (result.success) {
        if (result.requiresEmailFallback) {
          setShowEmailFallback(true);
          if (result.mailtoLink) setMailtoLink(result.mailtoLink);
        } else {
          setSuccess(true);
        }
      } else {
        setError(result.error ?? "Failed to send feedback. Please try again.");
      }
    } catch (error) {
      setError("Failed to send feedback. Please try again.");
    } finally {
      setLoading(false);
    }
  };

  const handleEmailFallback = () => {
    if (mailtoLink) window.open(mailtoLink, "_blank");
    setSuccess(true);
    setShowEmailFallback(false);
  };

  return (
    <div>
      <PopoverRoot>
        <PopoverTrigger disabled={loading}>
          {loading ? <span className="">Sending...</span> : "Feedback"}
        </PopoverTrigger>
        <PopoverContent align="end">
          <PopoverForm onSubmit={(data) => void handleSubmit(data)}>
            <PopoverHeader>Let us know what you think</PopoverHeader>
            <PopoverTextarea />
            <PopoverFooter>
              <PopoverCloseButton />
              <PopoverSubmitButton />
            </PopoverFooter>
          </PopoverForm>
        </PopoverContent>
      </PopoverRoot>
      <div className="mt-2 space-y-2">
        {success && <span className="text-green-500">Sent 🚀</span>}
        {error && <span className="text-red-500">{error}</span>}
        {showEmailFallback && (
          <div className="p-3 bg-blue-50 dark:bg-blue-950/20 border border-blue-200 dark:border-blue-800 rounded-lg">
            <div className="flex items-start gap-2">
              <Mail className="h-4 w-4 text-blue-600 dark:text-blue-400 mt-0.5" />
              <div className="space-y-2">
                <p className="text-xs text-blue-800 dark:text-blue-200">
                  Email service not configured. Click to open your email client:
                </p>
                <Button
                  type="button"
                  size="sm"
                  onClick={handleEmailFallback}
                  className="h-7 px-2 text-xs bg-blue-600 hover:bg-blue-700 text-white"
                >
                  <ExternalLink className="mr-1 h-3 w-3" />
                  Open Email
                </Button>
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

"use server";

import { z } from "zod";
import { createFeedback } from "@/server/services/feedback-service";

const feedbackSchema = z.object({
  content: z.string().min(1, "Feedback cannot be empty"),
  source: z.enum(["dialog", "popover"]),
  metadata: z.record(z.unknown()).optional(),
});

export const submitFeedback = async (input: z.infer<typeof feedbackSchema>) => {
  try {
    const validatedInput = feedbackSchema.parse(input);
    const result = await createFeedback(validatedInput);
    return result; // Return the FeedbackResult directly
  } catch (error) {
    console.error("Error submitting feedback:", error);
    return {
      success: false,
      error: error instanceof Error ? error.message : "Failed to submit feedback",
    };
  }
};

import { sql } from "drizzle-orm";
import { resend } from "@/lib/resend";
import { generateFeedbackMailto } from "@/lib/utils/email-utils";
import { db } from "@/server/db";
import { feedback } from "@/server/db/schema";
import { sendFeedbackEmail } from "@/server/services/resend-service";

export interface CreateFeedbackInput {
  content: string;
  source: "dialog" | "popover";
  metadata?: Record<string, unknown>;
}

export interface FeedbackResult {
  success: boolean;
  requiresEmailFallback?: boolean;
  mailtoLink?: string;
  data?: any;
  error?: string;
}

export const createFeedback = async (
  input: CreateFeedbackInput,
  options?: { skipEmail?: boolean }
): Promise<FeedbackResult> => {
  try {
    if (!input.content) {
      return { success: false, error: "Feedback content is required" };
    }

    if (input.content.length > 1000) {
      return { success: false, error: "Feedback content is too long" };
    }

    if (input.source !== "dialog" && input.source !== "popover") {
      return { success: false, error: "Invalid feedback source" };
    }

    if (input.metadata && typeof input.metadata !== "object") {
      return { success: false, error: "Invalid metadata" };
    }

    if (input.metadata && Object.keys(input.metadata).length > 10) {
      return { success: false, error: "Metadata cannot have more than 10 keys" };
    }

    // Try to save to database if available
    let dbResult = null;
    if (db) {
      try {
        const [result] = await db
          .insert(feedback)
          .values({
            content: input.content,
            source: input.source,
            metadata: JSON.stringify(input.metadata || {}),
          })
          .returning();
        dbResult = result;
      } catch (dbError) {
        console.warn("Database not available for feedback storage:", dbError);
      }
    }

    // Try to send email notification if not skipped
    if (!options?.skipEmail) {
      if (!resend) {
        // Resend not configured - require email fallback
        return {
          success: true,
          requiresEmailFallback: true,
          mailtoLink: generateFeedbackMailto(input.content, input.source),
          data: dbResult,
        };
      }

      try {
        await sendFeedbackEmail(input.content);
      } catch (emailError) {
        console.warn("Failed to send feedback email:", emailError);
        // Email failed but we saved to DB - suggest fallback
        return {
          success: true,
          requiresEmailFallback: true,
          mailtoLink: generateFeedbackMailto(input.content, input.source),
          data: dbResult,
        };
      }
    }

    return {
      success: true,
      requiresEmailFallback: false,
      data: dbResult,
    };
  } catch (error) {
    console.error("Error creating feedback:", error);
    return {
      success: false,
      error: error instanceof Error ? error.message : "Failed to create feedback",
    };
  }
};

export const getFeedback = async () => {
  // Graceful fallback: if no database is available, return empty array
  if (!db) {
    console.warn("Database not available, returning empty feedback list");
    return [];
  }

  try {
    return await db.select().from(feedback).orderBy(feedback.createdAt);
  } catch (error) {
    console.error("Error getting feedback:", error);
    throw new Error("Failed to get feedback");
  }
};

export const updateFeedbackStatus = async (id: string, status: string) => {
  if (!["pending", "reviewed"].includes(status)) {
    throw new Error("Invalid feedback status");
  }

  // Graceful fallback: if no database is available, log and return mock result
  if (!db) {
    console.warn("Database not available, feedback status update will not be persisted");
    return {
      id,
      content: "",
      source: "dialog" as const,
      metadata: "{}",
      status: status as "pending" | "reviewed",
      createdAt: new Date(),
      updatedAt: new Date(),
    };
  }

  const [result] = await db
    .update(feedback)
    .set({ status, updatedAt: new Date() })
    .where(sql`${feedback.id} = ${id}`)
    .returning();

  return result;
};
